---@param reportData LFightReportData
function LBattleLogicUnitMgr:LoadFromReport(reportData)
    self._reportData = reportData
    self._unitMap = {}
    self._teamA = {}
    self._teamB = {}
    self._freeUnitDataList = {}

    local formationDataA = reportData.formationA


    local teamAGrids = formationDataA.grids

    for k,v in pairs(teamAGrids) do
        self:AddUnit(v)
    end

    local teamType = BattleTeamSide.teamA
    -- 神器或精灵数据暂未完善
    local combatUnitsA = formationDataA.combatUnits
    if combatUnitsA then
        for k,v in ipairs(combatUnitsA) do
            local unitData = self:NewUnit(v.id)
            local type = v.type
            if type == LFightConst.OBJ_ARTIFACT then
                local initCD = v.data and v.data.initCD or 0
                unitData:InitializeArtifactData(tostring(v.id),v.refId,teamType,v.campSkillIdList,initCD)
                table.insert(self._teamAArtifact, unitData)
                self._teamAArtifactID = v.refId
                self._selfArtifactData = v.data
            elseif type == LFightConst.OBJ_TREASURE then
                unitData:InitTreasureData(v,teamType)
                self:AddFreeUnitData(unitData,type,teamType)
            end
        end

    end


    teamType = BattleTeamSide.teamB
    local formationDataB = reportData.formationB
    local teamBGrids = formationDataB.grids
    for k,v in pairs(teamBGrids) do
        self:AddUnit(v)
    end

    -- 神器或精灵数据暂未完善
    local combatUnitsB = formationDataB.combatUnits
    if combatUnitsB then
        for k, v in ipairs(combatUnitsB) do
            local unitData = self:NewUnit(v.id)
            local type = v.type
            if type == LFightConst.OBJ_ARTIFACT then
                local initCD = v.data and v.data.initCD or 0
                unitData:InitializeArtifactData(tostring(v.id),v.refId,teamType,v.campSkillIdList,initCD)
                table.insert(self._teamBArtifact, unitData)

                self._teamBArtifactID = v.refId
                self._otherArtifactData = v.data
            elseif type == LFightConst.OBJ_TREASURE then
                unitData:InitTreasureData(v,teamType)
                self:AddFreeUnitData(unitData,type,teamType)
            end
        end
    end

    self:UpdateHeroDataMap()

    self:InitHeroReliveSkillRecord()
end

function LBattleLogicUnitMgr:NewUnit(unitId)
    ---@type LBattleLogicUnit
    local unit = require("LApp.gameplay.videobattle.logic.obj.LBattleLogicUnit"):new(self._logicMgr)
    unit.id = unitId
    unit:Initialize()
    self._unitMap[unitId] = unit
    return unit
end


---@param unitData LBattleUnitGridData
function LBattleLogicUnitMgr:AddUnit(unitData)
    local unit = self._unitMap[unitData.id]
    if not unit then
        unit = self:NewUnit(unitData.id)
        unit:InitUnitData(unitData)

        if unit.teamType == BattleTeamSide.teamA then
            self._teamA[unitData.index] = unit
        else
            self._teamB[unitData.index] = unit
        end
    else
        unit:InitUnitData(unitData)
    end
    return unit
end

---@param unitData LBattleUnitGridData
function LBattleLogicUnitMgr:AddSummonUnit(unitData, belongSkin)
    local unit = self._unitMap[unitData.id]
    if not unit then
        unit = self:NewUnit(unitData.id)
        unit:InitSummonHeroData(unitData, belongSkin)
        if unit.teamType == BattleTeamSide.teamA then
            self._teamA[unitData.index] = unit
        else
            self._teamB[unitData.index] = unit
        end
    else
        unit:InitUnitData(unitData)
    end
    return unit
end

function LBattleLogicUnitMgr:InitHeroReliveSkillRecord()
    local record = {}
    for k,v in pairs(self._unitMap) do
        local tempRecord = v:GetReliveSkillRecord()
        for k1,v1 in pairs(tempRecord) do
            local map = record[k1]
            if not map then
                map = {}
                record[k1] = map
            end

            for k2,v2 in pairs(v1) do
                map[k2] = v2
            end
        end
    end

    self._reliveSkillRecord= record
end

function LBattleLogicUnitMgr:AddFreeUnitData(unitdata,type,side)
    local freeUnitDataList = self._freeUnitDataList
    if not freeUnitDataList then
        freeUnitDataList = {}
        self._freeUnitDataList = freeUnitDataList
    end
    local map = freeUnitDataList[type]
    if not map then
        map = {}
        freeUnitDataList[type] = map
    end
    map[side] = unitdata
end

function LBattleLogicUnitMgr:UpdateHeroDataMap()
    self._heroDataByIndex = {
        [BattleTeamSide.teamA] = {},
        [BattleTeamSide.teamB] = {},
    }

    for k,v in pairs(self._unitMap) do
        local objType = v:GetBattleObjType()
        if objType == LFightConst.OBJ_NORMAL or objType == LFightConst.OBJ_SUMMON or objType == LFightConst.OBJ_PET then
            local side = v:GetTeamType()
            local index = v:GetIndex()
            self._heroDataByIndex[side][index] = v
        end
    end

end

function LBattleLogicUnitMgr:GetHeroDataByIndex(side,index)
    if self._heroDataByIndex then
        return self._heroDataByIndex[side][index]
    end
end


--获取英雄heroData
function LBattleLogicUnitMgr:GetLogicUnit(aId)
    return self._unitMap[aId]
end

--所有阵容数据
function LBattleLogicUnitMgr:GetMapFormationData()
    return self._unitMap
end


function LBattleLogicUnitMgr:GetFormationA()
    return self._teamA
end

function LBattleLogicUnitMgr:GetFormationB()
    return self._teamB
end

function LBattleLogicUnitMgr:GetInfoShowFormation(side)
    local dataList = {}
    for k,v in pairs(self._unitMap) do
        if LFightConst.SHOW_ON_INFO[v:GetBattleObjType()] then
            if v:GetTeamType() == side then
                table.insert(dataList,v)
            end
        end
    end
    return dataList
end

---宝物数据
---@return LBattleLogicUnit
function LBattleLogicUnitMgr:GetBattleUnitData(type,side)
    if not self._freeUnitDataList then
        return
    end
    local map = self._freeUnitDataList[type]
    if not map then
        return
    end
    local data = map[side]
    return data
end

function LBattleLogicUnitMgr:CheckCanRelive(heroId, lifeState)
    if self:CheckSkillRecord(heroId,self._reliveSkillRecord) then
        return true
    end

    if self:CheckSkillRecord(heroId,lifeState) then
        return true
    end

    return false
end

function LBattleLogicUnitMgr:CheckSkillRecord(heroId,record)
    if not record then
        return false
    end
    local side = self:GetHeroSide(heroId)
    local tempSide = nil
    for k,v in pairs(record) do
        if v[1] then    ---可复活他人
        local heroData = self:GetLogicUnit(k)
            if not heroData then
                if LOG_INFO_ENABLED then
                    print("miss heroData "..k)
                end
            else
                if not heroData:IsDead() then
                    tempSide = self:GetHeroSide(k)
                    if tempSide == side then
                        return true
                    end
                end
            end

        elseif v[2] then  ---只能复活自己
        if heroId == k then
            return true
        end
        end
    end

    return false
end


function LBattleLogicUnitMgr:GetHeroSide(heroId)
    local heroData = self:GetLogicUnit(heroId)
    local side = heroData:GetTeamType()
    return side
end

---@param baseEffect LBattleBaseEffectData
---@return LBattleLogicUnit
function LBattleLogicUnitMgr:AddSummon(baseEffect)
    if not self._buffUIdToId then
        self._buffUIdToId = {}
    end
    local summonEffectData = baseEffect.summonEffect
    local buffUId = summonEffectData.buffUniqueId
    local heroId = self._buffUIdToId[buffUId]
    if heroId then
        return self._unitMap[heroId]
    end
    heroId = summonEffectData.hero.id
    --local side = summonEffectData.belong == 1 and BattleTeamSide.teamA or BattleTeamSide.teamB

    local callHero = self:GetLogicUnit(baseEffect.aId)
    local skin = callHero:GetSkinId()

    -- 【C宠物系统】删掉宠物系统相关
    -- if effect.hero.unitType == 3 then
    -- 	self:AddPetUnit(summonEffectData.hero,skin)
    -- else
    self:AddSummonUnit(summonEffectData.hero,skin)
    -- end

    self._buffUIdToId[buffUId] = heroId
end


function LBattleLogicUnitMgr:InsertWaitRemove(buffUId)
    if not self._buffUIdToId then return end

    local heroId = self._buffUIdToId[buffUId]
    if not heroId then return end

    if not self._waitRemoveHero then
        self._waitRemoveHero = {}
    end

    table.insert(self._waitRemoveHero,{heroId = heroId,buffUId = buffUId})
end

function LBattleLogicUnitMgr:RemoveSummonHero(removeData)
    local buffUId = removeData.buffUId
    self._buffUIdToId[buffUId] = nil
    local heroId = removeData.heroId
    self._unitMap[heroId] = nil

    if self._logicMgr then
        self._logicMgr:OnRemoveSummonHero(heroId)
    end
end

function LBattleLogicUnitMgr:CheckRemoveSummon()
    if not self._waitRemoveHero then
        return
    end

    for k,v in ipairs(self._waitRemoveHero) do
        self:RemoveSummonHero(v)
    end
end

function LBattleLogicUnitMgr:Dispose()
    if self._isDisposed then return end

    table.dispose(self)

    self._isDisposed = true
end

function LBattleLogicUnitMgr:OnUpdate(time, deltaTime)
    for k,v in pairs(self._unitMap) do
        v:OnUpdate(time, deltaTime)
    end
end

return LBattleLogicUnitMgr